"""Normalization helpers for credit PDF parsing."""

from __future__ import annotations

import re
from datetime import datetime
from typing import List, Optional, Set

_BUREAU_TAG_MAP = {
    "TUC": "transunion",
    "TU": "transunion",
    "TRANSUNION": "transunion",
    "EXP": "experian",
    "EXPERIAN": "experian",
    "EQX": "equifax",
    "EFX": "equifax",
    "EQUIFAX": "equifax",
}

_MONEY_RE = re.compile(r"\$?\s*([\d,]+(?:\.\d{2})?)")
_DATE_MDY = re.compile(r"\b(\d{1,2}/\d{1,2}/\d{2,4})\b")
_PAGE_BREAK = re.compile(r"--\s*\d+\s+of\s+\d+\s*--", re.IGNORECASE)

_SKIP_CREDITOR_LINES = re.compile(
    r"^(account number|ecoa|opened|credit history|current accounts|derogatory|disputed|"
    r"page \d|report id|order verifications|borrower|credit summary|file summary|"
    r"past due payment|account type|months reviewed|comment|summary)$",
    re.IGNORECASE,
)


def strip_page_breaks(text: str) -> str:
    return _PAGE_BREAK.sub("\n", text or "")


def parse_money(value: str) -> Optional[float]:
    if not value:
        return None
    match = _MONEY_RE.search(value)
    if not match:
        return None
    try:
        return float(match.group(1).replace(",", ""))
    except ValueError:
        return None


def parse_money_all(value: str) -> List[float]:
    return [v for v in (_parse_money_token(m) for m in _MONEY_RE.findall(value or "")) if v is not None]


def _parse_money_token(token: str) -> Optional[float]:
    try:
        return float(token.replace(",", ""))
    except ValueError:
        return None


def normalize_date(value: str) -> str:
    """Return YYYY-MM-DD when possible."""
    raw = (value or "").strip()
    if not raw:
        return ""
    for fmt in ("%m/%d/%Y", "%m/%d/%y", "%Y-%m-%d", "%m/%Y"):
        try:
            return datetime.strptime(raw[:10], fmt).strftime("%Y-%m-%d")
        except ValueError:
            continue
    return raw


def split_borrower_name(full_name: str) -> tuple[str, str]:
    parts = [p for p in full_name.strip().split() if p]
    if not parts:
        return "", ""
    if len(parts) == 1:
        return parts[0], ""
    return parts[0], " ".join(parts[1:])


def bureau_tags_from_text(text: str) -> Set[str]:
    """Map TUC-B1 / EXP-B1 / EQX-B1 (and comma-separated) to bureau keys."""
    found: Set[str] = set()
    upper = (text or "").upper()
    for token in re.findall(r"\b(TUC|EXP|EQX|TU)-B\d*\b", upper):
        prefix = token.split("-")[0]
        bureau = _BUREAU_TAG_MAP.get(prefix)
        if bureau:
            found.add(bureau)
    if "TRANSUNION" in upper or "TRANS UNION" in upper:
        found.add("transunion")
    if "EXPERIAN" in upper:
        found.add("experian")
    if "EQUIFAX" in upper:
        found.add("equifax")
    return found


def filter_for_bureau(items: List, bureau: str, attr: str = "reported_bureaus") -> List:
    out = []
    for item in items:
        tags = set(getattr(item, attr, None) or [])
        if not tags or bureau in tags:
            out.append(item)
    return out


def is_plausible_creditor_line(line: str) -> bool:
    line = line.strip()
    if len(line) < 2 or len(line) > 80:
        return False
    if _SKIP_CREDITOR_LINES.match(line):
        return False
    if is_city_state_line(line):
        return False
    if re.match(r"^\d{3}[-\s]?\d{2}[-\s]?\d{4}$", line):
        return False
    if re.match(r"^[\d\$\.,\s%]+", line):
        return False
    if line.lower().startswith("http"):
        return False
    return bool(re.search(r"[A-Za-z]", line))


_CITY_STATE_RE = re.compile(
    r"^[A-Za-z][A-Za-z\s\.\'-]+,\s*[A-Z]{2}(?:\s+\d{5}(?:-\d{4})?)?$"
)
_ZIP_ONLY_RE = re.compile(r"^\d{5}(?:-\d{4})?$")
_PHONE_RE = re.compile(r"^\d{3}[-.\s]?\d{3}[-.\s]?\d{4}$")


def is_city_state_line(line: str) -> bool:
    return bool(_CITY_STATE_RE.match((line or "").strip()))


def is_address_or_contact_line(line: str) -> bool:
    text = (line or "").strip()
    if not text:
        return True
    if is_city_state_line(text):
        return True
    if _ZIP_ONLY_RE.match(text):
        return True
    if _PHONE_RE.match(text):
        return True
    if re.match(r"^PO Box\b", text, re.I):
        return True
    if re.match(r"^P\.?\s*O\.?\s*Box", text, re.I):
        return True
    if re.match(r"^\d+\s+\w", text):  # street address
        return True
    if re.match(
        r"^(blvd|st|street|ave|avenue|dr|drive|rd|road|way|lane|ln|ct|court|ste|suite)\b\.?",
        text,
        re.I,
    ):
        return True
    return False


_CREDITOR_STOP_LINE_RE = re.compile(
    r"^(credit dispute|research team|comment|past due|payment|balance|released:|loan number:|\$\d)",
    re.I,
)


def is_creditor_boilerplate_line(line: str) -> bool:
    return bool(_CREDITOR_STOP_LINE_RE.match((line or "").strip()))
